import React, { useState } from "react";
import "./GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hi 👋 I’m your AI mental health assistant. How are you feeling today?"
    }
  ]);

  const [input, setInput] = useState("");
  const [isTyping, setIsTyping] = useState(false);

  const sendMessage = () => {
    if (!input.trim()) return;

    // Add user message
    const userMessage = { sender: "user", text: input };
    setMessages(prev => [...prev, userMessage]);
    setInput("");

    // Show typing indicator
    setIsTyping(true);

    // Simulate AI thinking
    setTimeout(() => {
      setIsTyping(false);

      const botReply = {
        sender: "bot",
        text: "I’m here with you 💜 Take your time. Would you like to tell me a bit more about what’s been on your mind?"
      };

      setMessages(prev => [...prev, botReply]);
    }, 1500);
  };

  return (
    <div className="chat-container">
      <div className="chat-title">🧠 General Chat</div>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`chat-message ${msg.sender}`}
          >
            {msg.text}
          </div>
        ))}

        {isTyping && (
          <div className="typing">
            AI is typing<span>.</span><span>.</span><span>.</span>
          </div>
        )}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type how you feel..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && sendMessage()}
        />
        <button onClick={sendMessage}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
